INSERT INTO `products` (`id`, `name`, `artist`, `category`, `genre`, `price`, `stock`, `description`, `image_url`, `format`, `music_genre`, `size`, `color`, `merch_type`, `instrument_subtype`, `accessory_type`, `created_at`, `updated_at`) VALUES
(1, 'Fender Stratocaster', 'Fender', 'Instruments', 'Guitars', 999.99, 6, 'Fender Stratocaster е електрическа китара, която от десетилетия задава стандарта за удобство, гъвкав тон и разпознаваем външен вид. Този модел е предпочитан както от начинаещи, които търсят надежден инструмент за първите си уроци и репетиции, така и от опитни музиканти, които искат ясна атака, добра динамика и усещане за прецизен контрол при всяко докосване на струните. Ергономичното тяло стои удобно както в седнало, така и в изправено свирене, а грифът позволява плавно движение по целия диапазон, което е важно при ритъм партии, сола и импровизации. Характерният звук е ясен, отворен и добре артикулиран, което прави Stratocaster подходящ за рок, блус, фънк, поп и алтернативна музика. Инструментът реагира отлично както на чист канал, така и на овърдрайв, като запазва отчетливост и характер дори в по-плътни миксове. Това е китара, с която можеш да репетираш у дома, да записваш в студио и да излизаш на сцена с увереност. Ако търсиш класически дизайн, удобство при дълго свирене и звук, който остава актуален независимо от стила, Fender Stratocaster е сигурен избор с истинска музикална стойност. Подходяща е за музиканти, които ценят баланс между традиция и универсалност, защото позволява лесно да изградиш собствен почерк и да се чувстваш естествено във всяка репетиционна, клуб или студио. Това е модел, който вдъхва увереност още от първото хващане.', 'images/strat.jpg', NULL, NULL, NULL, NULL, NULL, 'Електрически', NULL, '2025-11-20 16:19:14', '2026-03-25 08:37:47'),
(2, 'Gibson Les Paul Standard', 'Gibson', 'Instruments', 'Guitars', 1499.00, 3, 'Gibson Les Paul Standard е модел, който носи усещане за масивен тон, стабилност и силно сценично присъствие още от първия акорд. Това е китара, създадена за музиканти, които искат плътен звук с дълъг сустейн, богати среди и гладка реакция както при ритъм свирене, така и при изразителни сола. Формата и конструкцията вдъхват усещане за сериозен инструмент, а грифът е удобен за сигурен захват, прецизни преходи и уверен контрол върху динамиката. Les Paul Standard се справя еднакво добре с класически рок, хард рок, блус, метъл и модерни продукции, където е нужен по-дебел и наситен тон. На чист канал китарата звучи топло и обемно, а при усилване разгръща характерната си сила без да губи яснота в отделните ноти. Това я прави отличен избор за студийна работа, репетиции и живи участия, при които всеки детайл в звука има значение. Визията също е част от нейния чар, защото съчетава традиция, класа и незабавно разпознаваем стил. Ако търсиш инструмент с характер, тежест в тона и усещане за професионално ниво, Gibson Les Paul Standard остава една от най-уважаваните китари в историята на съвременната музика. Това е избор за музиканти, които не искат просто добра китара, а инструмент с авторитетен глас, плътно присъствие в микса и усещане за истинска сценична тежест. Подходяща е и за записи, в които се търси силен, запомнящ се характер.', 'images/lespaul.jpg', NULL, NULL, NULL, 'Cherry', NULL, 'Electric Guitar', NULL, '2025-11-20 16:19:14', '2026-03-25 08:37:47'),
(3, 'Yamaha P-45 Digital Piano', 'Yamaha', 'Instruments', 'Keyboards', 499.00, 7, 'Yamaha P-45 Digital Piano е практично и музикално решение за всеки, който иска усещане, близко до акустично пиано, без да прави компромис с удобството на съвременния дигитален инструмент. Моделът разполага с 88 клавиша и балансирано поведение, което подпомага правилната техника, развива контрола върху динамиката и прави упражненията по-естествени както за начинаещи, така и за напреднали пианисти. Звукът е чист, ясен и приятен за продължително свирене, независимо дали използваш инструмента за домашна практика, уроци, композиция или малки сценични участия. Компактният корпус позволява лесно разполагане в апартамент, учебна стая или студио, а семплият интерфейс прави работата с пианото интуитивна още от първото включване. Yamaha P-45 е подходящ избор за хора, които търсят надежден инструмент за ежедневни упражнения, защото съчетава стабилно усещане под пръстите, приятен тон и функционалност без излишно усложняване. Може да се използва със слушалки за тиха практика, което е голямо предимство в домашна среда, а лекотата при пренасяне го прави удобен и за преподаватели или музиканти в движение. Това е дигитално пиано, което поставя фокус върху най-важното: добра клавиатура, музикален звук и уверен комфорт при всяко свирене. Подходящо е и за хора, които преминават от синтезатор към по-сериозно обучение по пиано и имат нужда от инструмент, който насърчава правилни навици още от самото начало.', 'images/p45.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-25 08:37:47'),
(4, 'Pearl Drum Kit EXX725S', 'Pearl', 'Instruments', 'Drums', 799.00, 2, 'Pearl Drum Kit EXX725S е акустичен комплект барабани, създаден за музиканти, които искат пълноценен сет с истинско сценично усещане, добра издръжливост и балансиран тон още от първата репетиция. Конфигурацията тип EXX725S е позната с практичния си формат и обикновено включва бас барабан 22 инча, соло барабан 14 инча, два тома и един флор том, което дава ясен и подреден работен диапазон за рок, поп, метъл, фънк и училищни формации. Тялото на барабаните е проектирано така, че да предлага стегната атака, достатъчна дълбочина в ниските честоти и добър контрол върху резонанса, което е важно както за начинаещи, така и за барабанисти с вече изградена техника. Бас барабанът дава плътна основа, томовете реагират бързо при преходи, а солото позволява отчетлив удар с достатъчно присъствие в микса. Хардуерът е стабилен и подходящ за чести упражнения, защото държи настройката уверено и понася редовно сгъване, пренасяне и сценично натоварване. Визуално комплектът стои професионално и веднага създава усещане за сериозен инструмент, а размерите му са удобни както за домашна репетиционна, така и за клубна сцена. Това е добър избор за барабанист, който иска да развива координация, динамика и контрол върху цял сет, а не само върху отделни упражнения. Pearl е марка с дълга история при ударните инструменти и този модел носи типичната за нея идея за надеждност, практичност и музикален резултат. Ако търсиш комплект, с който да учиш правилна постановка, да свириш с група и да получиш реално усещане за акустични барабани, Pearl Drum Kit EXX725S е стойностна и сериозна отправна точка.', 'images/drumkit.jpg', NULL, NULL, NULL, NULL, NULL, 'Акустичен', NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(5, 'Boss DS-1 Distortion Pedal', 'Boss', 'Instruments', 'Effects', 59.00, 20, 'Boss DS-1 Distortion Pedal е един от най-разпознаваемите китарни ефекти в модерната музика и неслучайно присъства в педалбордовете на поколения рок, пънк, алтърнатив и соло китаристи. Педалът е компактен, здрав и създаден за реална употреба на сцена и в репетиционна, като характерният му оранжев корпус е лесен за разпознаване дори в тъмна среда. Управлението е изчистено и практично с три основни контроли за ниво, тон и степен на дисторшън, което позволява бърза настройка според усилвателя, китарата и стила на свирене. Звукът на DS-1 е известен с ярка атака, отчетлив ръб в горните среди и достатъчно дълъг сустейн за рифове, мелодични линии и сола, които трябва да изпъкват в микса. При по-ниски настройки педалът може да даде стегнат и агресивен драйв за ритъм китара, а при по-високи стойности създава по-наситено и плътно изкривяване с ясно присъствие. Това го прави полезен както за домашна практика, така и за записи, където е нужен класически транзисторен характер без излишно омекотяване на атаката. DS-1 се комбинира добре с чист канал, но работи убедително и като допълнителен цвят пред вече леко усилен лампов усилвател. Здравият футсуич механизъм и стандартното захранване го правят удобен за дългосрочна употреба и лесно интегриране в почти всеки сетъп. Ако търсиш педал с ясно изразена идентичност, бърза реакция и доказано място в рок историята, Boss DS-1 е практичен избор, който дава реален характер, а не просто още едно общо изкривяване. Това е ефект за китаристи, които искат звук с острота, енергия и уверен фокус във всяка репетиция или концерт.', 'images/ds1.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(6, 'Pink Floyd - The Wall', 'Pink Floyd', 'Music', 'Vinyl', 29.99, 15, 'Pink Floyd - The Wall е едно от най-значимите двойни рок издания в историята и албум, който съчетава силна концепция, мащабна продукция и запомнящи се композиции в цялостно слушателско преживяване. Това не е просто сбор от песни, а последователен разказ за изолация, натиск, вътрешни конфликти и изграждане на символична стена между човека и света около него. Още от първите минути се усеща кинематографичният подход на Pink Floyd към аранжимента, преходите и драматургията, а албумът постепенно развива напрежение чрез контраст между интимни моменти, сурови китари, театрални вокали и плътни клавирни пластове. В изданието присъстват едни от най-разпознаваемите песни на групата, включително Another Brick in the Wall, Comfortably Numb и Run Like Hell, но силата на The Wall е именно в цялостната форма, в която отделните песни работят като части от една по-голяма идея. За колекционери и любители на класическия рок това заглавие има трайна стойност, защото носи не само музикално качество, но и културно влияние, което продължава да се обсъжда и днес. Ако продуктът се слуша на винил, преживяването става още по-ритуално и концентрирано, защото двойнoтo издание насърчава слушане страна по страна и внимание към детайлите в записа. Албумът е подходящ за хора, които искат да се потопят в голяма рок концепция с литературно и емоционално измерение, а не просто да пуснат фонов плейлист. Това е заглавие, което звучи силно у дома, в аудиофилска система или като внимателно избран подарък за човек с вкус към класическия прогресивен рок. The Wall остава албум, към който се връщаш не само заради известните хитове, а заради усещането, че слушаш завършено произведение с идея, тежест и собствен свят.', 'images/thewall.jpg', NULL, 'Рок', NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(7, 'Metallica - Black Album', 'Metallica', 'Music', 'Vinyl', 24.99, 12, 'Metallica - Black Album е запис, който бележи решаващ момент в развитието на групата и в разширяването на тежката музика към много по-широка публика, без да губи усещането за сила, дисциплина и характер. Изданието от 1991 година е известно с масивния си, подреден и изключително добре продуциран звук, при който всеки инструмент има отчетливо място, а китарните рифове звучат едновременно тежко, стегнато и достъпно. Именно тук се намират песни като Enter Sandman, Nothing Else Matters, Sad But True и The Unforgiven, които и до днес са основна част от концертния репертоар на Metallica и от историята на хард рока и метъла. Албумът е особено ценен, защото комбинира агресия и мелодичност по начин, който работи еднакво добре за дългогодишни фенове на групата и за слушатели, които тепърва навлизат в жанра. Барабаните са плътни и авторитетни, басът присъства осезаемо, а вокалите стоят по-централно и уверено, което придава на целия запис силно радио и сценично въздействие. Ако държиш на издание, което звучи голямо и завършено от първата до последната песен, Black Album е основно заглавие за всяка метъл и рок колекция. Във винилов или CD формат този албум носи различно удоволствие от стрийминг слушането, защото акцентира върху целия звук, динамиката и реда на песните, а не само върху отделните хитове. Това е подходящ избор за домашно слушане с добра система, за подарък на фен или за колекция, която иска да включва безспорни класики с историческа тежест. Black Album остава пример как тежката музика може да бъде едновременно мощна, мелодична, модерна и запомняща се без да прави компромис с идентичността си.', 'images/blackalbum.jpg', NULL, 'Метъл', NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(8, 'Taylor Swift - Midnights', 'Taylor Swift', 'Music', 'CD', 14.99, 10, 'Taylor Swift - Midnights е албум, изграден около нощни мисли, тихо напрежение, синтезаторни текстури и внимателно написани поп песни, които се движат между интимност и модерен блясък. Заглавието е вдъхновено от идеята за безсънните часове, в които човек преговаря със спомени, самоувереност, съмнения и желания, а точно това усещане преминава през целия запис. Продукцията е гладка, детайлна и съвременна, като комбинира топли електронни слоеве, премерени бийтове и вокални линии, поставени в центъра на вниманието. В Midnights Taylor Swift показва способността си да превръща лични наблюдения в поп песни с широка емоционална разпознаваемост, без да губи фините нюанси в текста и атмосферата. Албумът работи добре както при фокусирано слушане със слушалки, така и като завършено вечерно издание за домашна система, защото детайлите в аранжимента постепенно се разкриват и създават много по-богато преживяване от първоначалното впечатление. Това е подходящ продукт за фенове на модерния поп, които ценят добре построена атмосфера, чиста мелодичност и продукция с усет към пространство и динамика. В CD формат изданието е удобно за колекция, подарък или ежедневно слушане в кола и у дома, а самият албум стои силно като самостоятелно произведение, а не само като сбор от успешни сингли. Midnights съчетава достъпност и авторски почерк, като предлага едновременно лекота и многопластов емоционален тон. Ако търсиш поп албум с модерно звучене, но и с личен характер, това заглавие е добър избор за колекция, в която място имат както актуални артисти, така и записи с ясно изразена концепция и идентичност.', 'images/midnights.jpg', NULL, 'Поп', NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(9, 'Eminem - Curtain Call', 'Eminem', 'Music', 'CD', 13.49, 18, 'Eminem - Curtain Call е компилация, която събира ключови моменти от една от най-влиятелните кариери в хип-хопа и представя развитието на Eminem чрез песни, превърнали се в част от масовата музикална култура. Това издание е особено подходящо както за дългогодишни почитатели, които искат удобно обобщение на най-силните му периоди, така и за слушатели, които тепърва искат да навлязат в каталога му чрез най-разпознаваемите заглавия. В селекцията присъстват песни, които показват различните страни на артиста: техническа скорост, саркастичен хумор, драматичен разказ, агресивна енергия и моменти на по-лична уязвимост. Точно това прави Curtain Call повече от стандартен best of албум, защото слушателят може ясно да усети колко широк е диапазонът на изпълнителя като автор и изпълнител. Продукцията на песните звучи уверено и разнообразно, с тежки бийтове, запомнящи се припеви и силно присъствие на гласа, което остава разпознаваемо още от първите секунди. Албумът е удобен избор за слушане в кола, у дома или като подарък за човек, който цени класическия мейнстрийм хип-хоп от началото на века. В CD формат колекцията запазва усещането за завършен музикален продукт и е практична за хора, които предпочитат физически носител пред плейлист. Това е заглавие, което комбинира комерсиален успех и реално жанрово значение, защото в него се вижда защо Eminem остава важна фигура не само за рапа, но и за по-широката поп култура. Ако търсиш издание с висока разпознаваемост, силна енергия и историческа тежест, Curtain Call е стабилно попълнение към всяка модерна музикална колекция.', 'images/curtaincall.jpg', NULL, 'Хип-Хоп', NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(10, 'Beethoven - Symphony No.9', 'Beethoven', 'Music', 'Vinyl', 19.99, 8, 'Beethoven - Symphony No.9 е издание, което носи величието на едно от най-влиятелните произведения в историята на класическата музика. Деветата симфония впечатлява с мащаб, драматично развитие и емоционален заряд, който остава еднакво силен както при първо слушане, така и при многократно връщане към отделните части. Още от началото произведението изгражда усещане за движение и напрежение, а финалът с Одата на радостта превръща записа в истинско културно преживяване, познато далеч извън концертната зала. Това винилово издание е подходящо както за колекционери, така и за слушатели, които искат да добавят в своята музикална библиотека класика с доказана художествена стойност. Форматът на плоча допринася за по-специален ритуал при слушане и насърчава внимателното потапяне в богатата оркестрация, хоровите моменти и контраста между тишина, драматизъм и тържественост. Албумът е отличен избор за спокойни вечери, за фокусирано слушане у дома или като подарък за човек с интерес към класическата традиция. Ако търсиш произведение, което съчетава историческо значение, силна емоция и музикална дълбочина, Beethoven - Symphony No.9 е заглавие, което заслужава постоянно място във всяка сериозна колекция. Това е запис, към който човек може да се връща отново и отново, откривайки нови детайли в темите, оркестъра и силата на човешкия глас. Всяко следващо слушане носи нов пласт смисъл.', 'images/beethoven9.jpg', NULL, 'Класически', NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-25 08:37:47'),
(11, 'MusicShop T-Shirt', '', 'Merch', 'Clothing', 19.99, 30, 'MusicShop T-Shirt е ежедневна тениска, създадена за хора, които искат да носят музикалната си идентичност по ненатрапчив, но разпознаваем начин. Моделът е изработен с акцент върху комфорт при продължително носене и е подходящ както за концерт, репетиция и фестивал, така и за обикновено градско ежедневие. Кройката е класическа и балансирана, което означава, че тениската стои добре както самостоятелно през топлите месеци, така и в комбинация с худи, яке или отворена риза. Материята е мека на допир и достатъчно дишаща, за да остане удобна през целия ден, а шевовете и обработката са подбрани така, че дрехата да запази формата си и след многократно пране. Логото на MusicShop дава ясен, но чист визуален акцент, без да превръща модела в агресивно рекламна дреха, което го прави лесен за комбиниране с дънки, къси панталони или по-небрежен сценичен стил. Черният или тъмен основен цвят обикновено е практичен избор за музикален мърч, защото подхожда на почти всичко и запазва визията си по-дълго при редовно носене. Тениската е подходяща и за подарък, особено ако търсиш полезен артикул, който няма да стои само в колекция, а реално ще се използва. Размер L предлага комфортно ежедневно прилягане за много потребители, без да ограничава движението в раменете и торса. Това е тип продукт, който съчетава практичност и принадлежност към музикална общност, без да разчита само на ефектна визия. Ако търсиш базова, носима и добре изглеждаща тениска с музикален характер, MusicShop T-Shirt е надежден избор за гардероб, концертна визия или фенска колекция.', 'images/tshirt_musicshop.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(12, 'Metallica Hoodie', 'Metallica', 'Merch', 'Clothing', 49.99, 12, 'Metallica Hoodie е официален мърч артикул, който комбинира разпознаваемата визуална идентичност на групата с удобството на дреха, създадена за ежедневно носене през по-хладните месеци. Худито е подходящо както за концертна вечер, така и за училище, университет, пътуване или спокойни дни, в които искаш по-топъл и удобен слой с ясно изразен рок характер. Материята обикновено е смес от памук и полиестер, което позволява добра комбинация между мекота отвътре, стабилност на формата и по-лесна поддръжка при редовна употреба. Вътрешната част създава приятно усещане при носене, а качулката добавя практичност при вятър и студ, без да нарушава силуета на дрехата. Предният джоб тип кенгуру е полезен както за ръце, така и за дребни ежедневни вещи, а ластичните маншети и подгъв помагат худито да стои събрано и удобно. Дизайнът с Metallica обикновено се възприема не само като фенски символ, но и като част от класическата рок естетика, което прави дрехата лесна за съчетаване с дънки, тъмни панталони и кецове. Размер XL е подходящ за хора, които предпочитат по-свободна и удобна кройка, особено ако дрехата ще се носи върху тениска или тънка блуза. Това е артикул, който има реална стойност и извън чисто колекционерския интерес, защото се използва ежедневно и носи комфорт, а не само лого. Ако търсиш практично рок худи с добра функционалност, ясно присъствие и усещане за автентичен бранд мърч, Metallica Hoodie е силен избор както за лична употреба, така и за подарък на фен на групата.', 'images/hoodie.jpg', NULL, NULL, 'S, M, L', 'Черен', 'Худи', NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(13, 'Pink Floyd Mug', 'Pink Floyd', 'Merch', 'Drinkware', 9.99, 25, 'Pink Floyd Mug е практичен мърч продукт, който пренася разпознаваема визия на групата в един от най-използваните ежедневни аксесоари у дома или в офиса. Чашата е изработена от керамика, материал, който задържа топлината добре, стои стабилно в ръката и е подходящ за кафе, чай, горещ шоколад или всяка друга любима напитка през деня. Дизайнът, вдъхновен от Pink Floyd и конкретно от класически визуални мотиви, добавя силен културен акцент, без продуктът да губи своята основна практична функция. Белият или светъл фон позволява графиката да изпъкне ясно, а гладката повърхност прави чашата лесна за почистване и удобна за ежедневна употреба. Формата е стандартна и удобна, с дръжка, която осигурява стабилен захват, а вместимостта е подходяща за нормална порция напитка, без чашата да изглежда прекалено обемиста на бюро или кухненски рафт. Това е добър избор за хора, които искат да включат музикалния си вкус в работната среда, домашния ритуал за сутрешно кафе или малки моменти на почивка. Освен полезен, продуктът е и лесен подарък за фен на Pink Floyd, защото не изисква точен размер, не е сезонен и реално влиза в ежедневието. Чашата стои добре както самостоятелно, така и като част от тематична колекция с плочи, тениски и постери. Ако търсиш мърч, който не стои само за украса, а се използва редовно и носи усещане за принадлежност към една от най-важните групи в рок историята, Pink Floyd Mug е разумен и приятен избор. Това е малък артикул с голяма практическа стойност и с достатъчно характер, за да радва всеки ден.', 'images/mug.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(14, 'AC/DC Keychain', 'AC/DC', 'Merch', 'Other', 4.99, 50, 'AC/DC Keychain е компактен мърч аксесоар, който комбинира практичната функция на ключодържател с ясно разпознаваемата визуална идентичност на една от най-емблематичните рок групи. Изработен е така, че да бъде достатъчно здрав за ежедневно носене в джоб, раница, калъф за инструмент или автомобилен ключ, без да създава излишна тежест и неудобство. Металният или комбиниран корпус придава по-стабилно усещане и издържа по-добре на редовно триене, преместване и контакт с други предмети, което е важно за аксесоар, който постоянно е в движение. Логото на AC/DC добавя мигновено разпознаване и прави продукта подходящ както за дългогодишни фенове, така и за хора, които просто искат малък рок акцент в ежедневието си. Халката е проектирана да държи сигурно няколко ключа, а компактният размер позволява ключодържателят да не пречи при носене и използване. Това е добър избор и за подарък, защото не зависи от размер, сезон или специална поддръжка, а в същото време има личен характер и музикална стойност. Може да се използва и като декорация за цип на калъф, раница или друг аксесоар, което разширява функционалността му отвъд стандартното приложение. Сребристият или метален завършек обикновено пасва добре на рок естетиката и създава усещане за по-качествено изпълнение спрямо евтините пластмасови алтернативи. Ако търсиш малък, достъпен и реално полезен мърч продукт, който носи духа на класическия рок, AC/DC Keychain е удачен избор за всекидневна употреба. Това е тип аксесоар, който не стои в кутия, а наистина влиза в ритъма на деня и напомня за любимата музика при всяко излизане.', 'images/keychain.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(15, 'Nirvana Cap', 'Nirvana', 'Merch', 'Clothing', 24.99, 14, 'Nirvana Cap е ежедневна шапка с козирка, която носи визуалния дух на гръндж културата и в същото време остава практичен аксесоар за градска употреба, пътуване и летни концерти. Моделът е проектиран така, че да стои удобно върху главата без излишно напрежение, като регулируемото закопчаване позволява лесно нагласяне според индивидуалния размер и предпочитание за по-плътно или по-свободно прилягане. Извитата козирка предпазва очите от слънце и прави шапката полезна не само като мърч, но и като реален функционален аксесоар в ежедневието. Черният цвят е универсален и лесен за комбиниране с тениски, худита, дънкови якета и по-небрежен рок стил, а емблематичната усмивка на Nirvana дава силно разпознаваем акцент без нужда от прекалено сложен дизайн. Материята е подходяща за редовно носене, като поддържа форма и не изглежда тежка или неудобна дори при по-дълго използване навън. Това прави продукта удачен за разходки, пътуване, фестивали и ежедневна визия, в която музикалният вкус присъства естествено. Шапката е и практичен подарък, защото се адаптира към различни хора чрез регулируемия механизъм и не изисква специфична грижа извън обичайното почистване. За феновете на Nirvana този артикул е повече от просто аксесоар, защото носи асоциация с цяла епоха в алтернативната музика. Ако търсиш мърч, който можеш да използваш реално, а не само да държиш като сувенир, Nirvana Cap е добър избор с ясно изразен характер, удобство и лесна ежедневна приложимост. Това е аксесоар, който стои еднакво добре както в уличен стил, така и като част от по-спокойна, изчистена рок визия.', 'images/cap.jpg', NULL, NULL, 'All-Size', 'Черен', 'Шапка', NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(16, 'Guitar Stand', '', 'Other', 'Stands', 15.99, 40, 'Guitar Stand е универсална стойка за китара, предназначена да осигури сигурно и удобно място за съхранение на инструмента у дома, в репетиционна, студио или на сцена. Вместо китарата да се оставя върху легло, стол или директно на пода, стойката поддържа корпуса в стабилна позиция и намалява риска от случайни удари, изплъзване и натиск върху грифа. Конструкцията е съобразена с общите форми на акустични и електрически китари, което я прави практичен избор за музиканти с повече от един инструмент или за пространства, в които се сменят различни модели. Контактните точки обикновено са покрити с мек защитен материал, за да не се надраска финишът на инструмента и да се избегне директен контакт между дърво или лак и металната рамка. Сгъваемият или лек дизайн улеснява пренасянето, което е важно за хора, които ходят на уроци, репетиции и участия и искат аксесоар, който не заема излишно място в багажника. Черният цвят е неутрален и стои дискретно в почти всяка среда, без да отвлича вниманието от самата китара. Добрата стойка е малък, но важен аксесоар, защото насърчава и по-честото свирене: когато инструментът е подръка и безопасно поставен, много по-лесно посягаш към него за кратка практика или идея. Това я прави полезна както за начинаещи, така и за активни музиканти с натоварен график. Ако търсиш практично решение за организиране на пространството и защита на китарата между отделните свирения, Guitar Stand е разумна инвестиция с реална ежедневна стойност. Това е аксесоар, който не се забелязва веднага, но бързо се превръща в задължителна част от нормалната грижа за инструмента.', 'images/stand.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(17, 'Instrument Cable 3m', '', 'Other', 'Cables', 9.99, 60, 'Instrument Cable 3m е базов, но изключително важен аксесоар за всеки музикант, който използва електрическа китара, бас, клавир, педали или друго оборудване с инструментален жак. Дължината от три метра е добре балансиран избор, защото дава достатъчно свобода за движение около усилвател, педалборд или аудио интерфейс, без кабелът да става прекалено дълъг, тежък и неудобен за ежедневна употреба. Кабелът е подходящ както за домашни репетиции и упражнения, така и за малки сцени, училищни изяви и студийни приложения, където надеждната връзка между устройствата е критична. Добре изработеният инструментален кабел трябва да осигурява стабилен сигнал, минимален шум и устойчивост при многократно включване, навиване и пренасяне, а именно това се очаква от подобен модел. Стандартните жак конектори 6.35 мм позволяват широка съвместимост с усилватели, ефекти, интерфейси и повечето музикални инструменти, което го прави универсално решение за различни сетъпи. Външната обвивка обикновено е достатъчно гъвкава, за да се навива лесно, но и достатъчно здрава, за да понесе редовна употреба в активна среда. Това е един от онези продукти, които често остават на заден план, но всъщност имат огромно значение за чистотата на сигнала и спокойствието по време на свирене. Кабелът е подходящ както като основен, така и като резервен в калъф или педалборд, защото винаги е разумно да има допълнителна надеждна връзка под ръка. Ако търсиш практичен инструментален кабел с удобна дължина и широка съвместимост, Instrument Cable 3m е стабилна ежедневна основа за всеки музикален сетъп. Това е аксесоар, без който дори най-добрият инструмент не може да разгърне пълния си потенциал в реална употреба.', 'images/cable.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'JACK - JACK', '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(18, 'Microphone Pop Filter', '', 'Other', 'Accessories', 12.99, 22, 'Microphone Pop Filter е полезен студиен аксесоар, който подобрява качеството на вокалните записи чрез намаляване на рязките въздушни удари при произнасяне на съгласни като п, б и т. Тези така наречени плозиви често създават неприятни нискочестотни удари в микрофона и могат да развалят иначе добър запис, особено при близко позициониране на изпълнителя. Поп филтърът се поставя между устата и микрофона и действа като защитен слой, който разсейва въздушната струя, без да пречи съществено на естествения тон на гласа. Това го прави почти задължителен инструмент за домашни студиа, подкаст записи, озвучаване, стрийминг и всяка ситуация, в която се търси по-чист и контролиран вокален резултат. Конструкцията обикновено включва гъвкаво рамо и здрава щипка, така че аксесоарът да може лесно да се закрепи към стойка за микрофон и да се нагласи в най-удобната позиция. Черният цвят е практичен и ненатрапчив, а кръглата форма покрива достатъчно голяма зона пред капсулата на микрофона. Освен че намалява плозивите, поп филтърът често помага и на изпълнителя да запази по-постоянна дистанция до микрофона, което води до по-стабилно ниво и по-предсказуем запис. Това е особено ценно за начинаещи вокалисти и създатели на съдържание, които все още изграждат техника пред микрофон. Ако искаш домашните ти записи да звучат по-подредено, професионално и приятно за слушане, Microphone Pop Filter е малка, но много смислена инвестиция. Това е аксесоар, който не променя гласа ти изкуствено, а просто помага той да бъде уловен по-чисто, уверено и без излишни технически дефекти.', 'images/popfilter.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'Поп-филтри', '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(19, 'Studio Headphones', '', 'Other', 'Audio', 89.99, 10, 'Studio Headphones са затворен тип слушалки, предназначени за мониторинг, фокусирано слушане и работа в среда, в която е важно звукът да остане ясен, контролиран и относително изолиран от външен шум. Затвореният дизайн обхваща ухото по начин, който ограничава изтичането на звук навън и намалява влиянието на околната среда, което е полезно при запис на вокали, домашно продуциране, подкаст работа и спокойно детайлно слушане вечер. Този тип слушалки са предпочитани, когато се търси по-точна представа за ритъм, панорама и баланс, без микрофонът наблизо да улавя прекалено много от възпроизвеждания сигнал. Меките наушници и регулируемата лента за глава са важни за комфорта при по-дълги сесии, а именно това прави подобен модел удачен както за начинаещи продуценти, така и за музиканти, които записват демо идеи у дома. Черният цвят и изчистеният дизайн им придават професионален вид и ги правят подходящи за студио, учебна стая и мобилен сетъп. При добре настроени студийни слушалки басът не е изкуствено напомпан, а средите и високите честоти остават достатъчно отчетливи, за да се чуват вокали, китари, клавири и дребни детайли в микса. Това ги отличава от масовите слушалки за развлечение, които често са по-ефектни, но по-малко полезни за реална работа със звук. Ако търсиш модел за запис, редактиране, упражнения с електронни инструменти или просто по-съсредоточено слушане, Studio Headphones са практичен избор с широка приложимост. Това е оборудване, което помага да чуваш повече, да работиш по-спокойно и да вземаш по-добри решения при всяка творческа сесия.', 'images/headphones.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'Closed-Back', '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(20, 'USB Audio Interface', 'Focusrite', 'Other', 'Recording', 129.99, 6, 'USB Audio Interface е централният елемент в почти всяко домашно студио, защото именно той свързва микрофони, инструменти и слушалки с компютъра по начин, който осигурява по-добро качество, по-нисък шум и по-надежден контрол от вградената звукова карта. Интерфейс с два входа е особено практичен вариант, тъй като позволява едновременно включване например на микрофон и китара, на два микрофона или на друг малък записващ сетъп, подходящ за демо записи, подкаст, стрийминг и продукция у дома. Стандартно при този тип устройство се очакват комбинирани входове, контрол на входното ниво, изход за слушалки, основен контрол на силата и възможност за директен мониторинг, което прави работата по-удобна и намалява неприятното закъснение при запис. Ако интерфейсът предлага фантомно захранване, той може да се използва и с кондензаторни микрофони, което значително разширява приложението му за вокали и акустични инструменти. Компактният размер е голямо предимство, защото устройството може лесно да стои на бюро до лаптоп, MIDI клавиатура и малки монитори, без да изисква специално студийно пространство. Червеният корпус или ярък цвят често не е само дизайнерски жест, а прави интерфейса лесен за разпознаване сред останалата техника. Това е продукт за хора, които искат да преминат от идея към реален запис с по-добър звук, по-ясен сигнал и повече контрол върху процеса. Ако записваш вокали, китара, подкаст или онлайн уроци, USB Audio Interface е оборудване, което вдига качеството на целия сетъп осезаемо. Това е основа, върху която можеш да изградиш работещо студио у дома без излишна сложност, но с реален професионален ефект.', 'images/interface.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'Audio Interface', '2025-11-20 16:19:14', '2026-03-26 10:33:05'),
(21, 'Ibanez GSR200 Bass', 'Ibanez', 'Instruments', 'Basses', 269.00, 3, 'Ibanez GSR200 Bass е четириструнен бас, създаден като достъпна и надеждна входна точка към света на бас китарата, без да се прави компромис с удобството, основния тон и усещането за истински инструмент. Този модел е популярен сред начинаещи и междинни музиканти, защото комбинира леко тяло, сравнително тънък и удобен гриф и електроника, която позволява лесно оформяне на звука според стила и групата. Конструкцията е насочена към комфортно свирене в седнало и изправено положение, което е важно при дълги упражнения, репетиции и първи участия. Четирите струни предлагат класическия бас диапазон, необходим за рок, поп, метъл, фънк и учебни ансамбли, а характерът на инструмента е достатъчно гъвкав, за да работи и с пръсти, и с перце. GSR200 е известен с това, че реагира бързо и предвидимо, което помага на свирещия да развива тайминг, контрол над динамиката и увереност в ниския регистър. Балансът между корпуса и грифа прави инструмента по-малко уморителен за начинаещи, а общата ергономия е насочена към музиканти, които искат да се концентрират върху свиренето, а не върху борба с неудобен инструмент. Басът е подходящ за домашни упражнения с усилвател, за училищни групи, първи студийни опити и редовни репетиции с банда. Марката Ibanez е добре позната с удобните си грифове и практичен дизайн, а това се усеща ясно и тук. Ако търсиш достъпен бас с реален потенциал за развитие, Ibanez GSR200 Bass е модел, който може да служи не само като първи инструмент, а и като надежден партньор дълго след началния етап на обучение.', 'images/products/ibanez-bass.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-13 09:02:57', '2026-03-26 10:33:05'),
(22, 'Akustichna kitara', '', 'Instruments', 'Guitars', 20.00, 5, 'Akustichna kitara e testow produkt sus snimka ot internet, a ne ot lokal na papka', 'https://images.squarespace-cdn.com/content/v1/57f5648637c581229b2e436f/1561988003374-K92XU2EQFH13QJOPOMU2/80-front.jpg?format=500w', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-13 10:01:59', '2026-03-26 12:08:15'),
(23, 'elektricheska kitara', '', 'Instruments', 'Guitars', 4000.00, 0, 'testow produkt sus snimka ot lokalna papka\n', 'images/products/elektricheska_kitara.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-13 10:05:22', '2026-03-26 12:07:08'),
(24, 'Focusrite Scarlett Solo Studio Pack', 'Focusrite', 'Instruments', 'Studio', 249.00, 5, 'Focusrite Scarlett Solo Studio Pack е цялостен стартов комплект за домашно студио, създаден така, че да даде на един начинаещ или междинен музикант почти всичко необходимо за запис на вокали и инструменти в компактен и лесен за използване формат. В центъра на пакета стои аудио интерфейсът Scarlett Solo, който е известен с чистите си предусилватели, удобния контрол и възможността да свържеш микрофон и инструмент директно към компютър за бърз и качествен запис. Към него обикновено се добавят кондензаторен микрофон и студийни слушалки, което превръща комплекта в реално работещо решение за вокали, акустична китара, електрическа китара през вход за инструмент, подкаст, стрийминг и онлайн съдържание. Голямото предимство на такъв пакет е, че компонентите са подбрани да работят заедно, а това спестява време, несигурност и допълнителни разходи при сглобяване на студио от отделни части. Интерфейсът е достатъчно компактен за бюро в апартамент или малка стая, а качеството на звука е на ниво, което позволява не само упражнения, но и сериозни демо записи и публикации онлайн. Микрофонът помага за детайлно улавяне на гласа, слушалките дават контрол върху мониторинга, а интерфейсът обединява целия процес в ясен работен център. Това е отличен избор за певци, китаристи, автори на песни и създатели на съдържание, които искат бърз старт без сложна техника. Червеният дизайн на Focusrite е вече разпознаваем символ за достъпно, но сериозно домашно студио. Ако търсиш комплект, който позволява да започнеш запис веднага и да получиш истинско подобрение в качеството спрямо вграден микрофон и обикновена звукова карта, Scarlett Solo Studio Pack е един от най-практичните варианти в този клас.', 'images/products/focusrite-pack.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-23 09:00:00', '2026-03-26 10:33:05'),
(25, 'Pioneer DJ DDJ-FLX4', 'Pioneer DJ', 'Instruments', 'DJ', 329.00, 4, 'Pioneer DJ DDJ-FLX4 е двуканален DJ контролер, насочен към начинаещи и мобилни диджеи, които искат модерен, лесен за усвояване и същевременно достатъчно сериозен инструмент за реални сетове, домашна практика и първи участия. Контролерът работи с популярни платформи като rekordbox и Serato DJ Lite, което го прави удобна отправна точка към съвременния дигитален DJ свят без нужда от сложна отделна апаратура. Разположението на бутоните, джоговете и фейдърите е интуитивно и близко до логиката на по-големите клубни системи, така че уменията, изградени върху FLX4, се пренасят сравнително лесно и към по-професионални конфигурации. Моделът е компактен, лек и подходящ за бюро, малко студио, бар, частно събитие или пренасяне в раница, а USB захранването улеснява работата с лаптоп без излишни кабели и външни адаптери. Функции като Smart Fader и Smart CFX помагат на начинаещите да правят по-гладки преходи и по-интересни миксове, без да заменят нуждата от истинска техника, а просто правят ученето по-достъпно и мотивиращо. Контролерът позволява работа с hot cues, loop функции, EQ и ефекти, което е достатъчно за изграждане на стабилна основа в бийтмачинг, подреждане на сет и сценично поведение. Черният корпус изглежда професионално и се вписва добре както в домашен, така и в мобилен DJ сетъп. Ако търсиш устройство, което да ти даде реално усещане за миксиране, добра софтуерна съвместимост и възможност да се развиваш постепенно, Pioneer DJ DDJ-FLX4 е един от най-смислените избори в началния и средния клас.', 'images/products/flx4.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-23 09:00:00', '2026-03-26 10:33:05'),
(26, 'Marshall MG15G Practice Amp', 'Marshall', 'Instruments', 'Amps', 139.00, 6, 'Marshall MG15G Practice Amp е компактен транзисторен китарен усилвател, създаден за домашни упражнения, уроци и малки репетиционни ситуации, в които е нужен разпознаваем китарен характер без прекомерна мощност и сложност. С номинална мощност около 15 вата този модел е достатъчно силен, за да даде истинско усещане за усилвател в стая, но остава удобен за контролиране в домашна среда, където прекалено силният звук би бил проблем. Marshall традиционно се свързва с рок тон и именно това присъствие се усеща и тук, особено когато се използва овърдрайв каналът за по-агресивни рифове и сола. Чистият канал е полезен за упражнения, за педали и за по-леки стилове, а еквалайзерът позволява базово оформяне на ниски, среди и високи честоти според китарата и помещението. Компактният кабинет и вграденият говорител правят усилвателя лесен за преместване между стаи, уроци и малки репетиции, без да се губи усещането за истински хардуер, а не за цифрова играчка. Входът за слушалки е особено полезен при вечерна практика, а допълнителният вход за външен източник позволява свирене върху бек тракове или уроци. Черният дизайн с типичната Marshall визия добавя и класическо сценично усещане, което винаги вдъхновява повече от безлична пластмасова техника. Това е усилвател за китаристи, които искат да репетират редовно, да развиват ритъм и техника и да чуват инструмента си по реален начин. Ако търсиш практичен тренировъчен усилвател с рок характер, лесно управление и надеждно ежедневно приложение, Marshall MG15G е стабилен избор за домашен сетъп.', 'images/products/practice-amp.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-23 09:00:00', '2026-03-26 10:33:05'),
(27, 'Shure SM58 Vocal Microphone', 'Shure', 'Instruments', 'Microphones', 119.00, 9, 'Shure SM58 Vocal Microphone е един от най-известните динамични вокални микрофони в света и модел, който от десетилетия е стандарт за сцена, репетиционна и озвучаване на живо. Популярността му не е случайна, защото SM58 съчетава здравина, предвидим звук и отличен контрол в реални условия, където микрофонът трябва да работи стабилно вечер след вечер. Динамичната капсула е подходяща за вокали с различна сила и характер, а кардиоидната насоченост помага да се изолира основният източник и да се намалят страничните шумове и рискът от микрофония. Това прави модела особено полезен за клубни участия, училищни сцени, репетиции с банда, реч, водене на събития и дори за домашни записи, когато се търси по-стегнат и директен резултат. Характерният сферичен грил включва вътрешна защита срещу дъх и леки плозиви, което подобрява практическата работа с микрофона без нужда от много допълнителни аксесоари. Звукът на SM58 е ясен и фокусиран в средния диапазон, така че гласът да се чува отчетливо в микса и през озвучителна система. Здравият метален корпус е създаден да понесе пътуване, изпускане и постоянна употреба, което е една от причините този микрофон да се използва толкова широко по света. Ако търсиш модел, на който можеш да разчиташ за репетиции, концерти и дългосрочна работа, Shure SM58 е избор с доказана репутация, а не временен компромис. Това е микрофон, който не впечатлява с излишна показност, а с последователна надеждност, ясен вокален фокус и истинска практическа стойност.', 'images/products/shure.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-23 09:00:00', '2026-03-26 10:33:05'),
(28, 'DAddario Guitar Care Kit', 'DAddario', 'Instruments', 'Accessories', 24.90, 11, 'DAddario Guitar Care Kit е комплект за поддръжка, създаден за китаристи, които разбират, че доброто състояние на инструмента влияе не само на външния вид, но и на усещането при свирене, стабилността на хардуера и дългосрочния живот на грифа и корпуса. В такъв комплект обикновено се включват препарати за почистване и полиране, кърпа и помощни средства, с които инструментът може да бъде поддържан чист след редовно свирене, транспорт и контакт с прах, пот и кожни мазнини. Именно тези дребни натрупвания често водят до загуба на блясък, по-неприятно усещане по струните и по-бързо замърсяване на повърхностите около адаптери, мост и гриф. Комплектът е подходящ както за електрически, така и за акустични китари, стига да се използва внимателно според финиша и препоръките за инструмента. Голямото му предимство е, че събира на едно място най-нужното за основна грижа и така улеснява музиканта да изгради редовен навик за поддръжка вместо да отлага почистването. Добре поддържаната китара не само изглежда по-добре, но често и се усеща по-комфортно в ръцете, което насърчава по-честа практика и повече уважение към самия инструмент. Това прави комплекта удачен избор за лична употреба, за подарък на начинаещ китарист или като полезно допълнение към покупка на нова китара. Марката DAddario е добре позната в света на китарните аксесоари и именно това създава доверие, че продуктът е насочен към реална музикална употреба. Ако търсиш лесен начин да пазиш инструмента си чист, представителен и приятен за свирене, този Guitar Care Kit е разумна и практична инвестиция.', 'images/carekit.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-23 09:00:00', '2026-03-26 10:33:05'),
(29, 'Ortega Instrument Starter Bundle', 'Ortega', 'Instruments', 'Other', 49.00, 7, 'Ortega Instrument Starter Bundle е начален комплект аксесоари, предназначен да даде на новия собственик на инструмент най-необходимите дребни допълнения за по-удобен старт още от първия ден. Вместо човек да търси отделно перца, колан, тунер и други основни принадлежности, подобен bundle събира полезните елементи в едно пакетно решение и така улеснява както начинаещия музикант, така и родител или приятел, който купува подарък. Комплектът е особено подходящ за китара, укулеле или друг подобен струнен инструмент, при който правилното настройване, удобното държане и наличието на резервни дребни аксесоари правят ученето много по-приятно. Практичността тук е основният плюс: тунерът помага инструментът да звучи вярно, перцата дават избор на усещане при свирене, а коланът или другите включени принадлежности улесняват ежедневната употреба. Брандът Ortega е свързан със струнни инструменти и аксесоари, така че пакетът носи усещане за по-целенасочено решение, а не за случаен набор от евтини дреболии. Подобен комплект е ценен и за музиканти, които вече имат инструмент, но искат резервни или допълнителни аксесоари за калъф, репетиционна или пътуване. Това е продукт, който не изглежда впечатляващо на пръв поглед, но има реално значение за удобството на старта и за по-лесното изграждане на навик за свирене. Ако търсиш полезен, достъпен и смислен комплект за нов музикант, Ortega Instrument Starter Bundle е практично решение, което събира малките, но важни неща в една удобна покупка. Именно такива аксесоари често правят разликата между хаотично начало и подреден, мотивиращ първи контакт с инструмента.', 'images/products/ortega.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-23 09:00:00', '2026-03-26 10:33:05'),
(30, 'Daft Punk - Random Access Memories Download Card', 'Daft Punk', 'Music', 'Digital', 11.99, 25, 'Daft Punk - Random Access Memories Download Card е дигитално издание на албум, който се превърна в ключов момент в съвременната поп и електронна музика чрез впечатляваща продукция, живи инструменти и внимателно конструирана атмосфера. За разлика от много други електронни записи, този албум поставя силен акцент върху органичния груув, бас линиите, китарните детайли и уважението към диско, фънк и студийния звук от по-ранни десетилетия. Композиции като Get Lucky, Instant Crush и Giorgio by Moroder показват колко успешно Daft Punk обединяват ретро вдъхновение и модерна прецизност в запис, който звучи едновременно носталгично и изключително актуално. Форматът download card е удобен за слушатели, които предпочитат бърз достъп до висококачествени файлове без нужда от физически диск, но все пак искат официално издание, а не просто поток от стрийминг платформа. Това е особено практично за хора, които слушат музика на компютър, аудио плейър или домашен сървър и държат на по-добър контрол над файловете си. Албумът сам по себе си е чудесен избор за вечерно слушане, за добра домашна система или слушалки, защото продукцията му е богата на детайли, пространство и динамика. Download card форматът често включва и дигитална книжка, която добавя още стойност чрез визуален и информационен контекст. Ако търсиш издание с висока музикална репутация, стилен звук и удобство на съвременния дигитален носител, Random Access Memories е отлична добавка към всяка колекция. Това е албум, който не разчита само на един хит, а предлага последователно изградена атмосфера, в която техническото качество и музикалната идея вървят ръка за ръка.', 'images/products/daft-punk-random-access-memories.jpg', 'Digital Download', 'Electronic', NULL, NULL, NULL, NULL, NULL, '2026-03-23 10:00:00', '2026-03-26 10:33:05');
INSERT INTO `products` (`id`, `name`, `artist`, `category`, `genre`, `price`, `stock`, `description`, `image_url`, `format`, `music_genre`, `size`, `color`, `merch_type`, `instrument_subtype`, `accessory_type`, `created_at`, `updated_at`) VALUES
(31, 'Nirvana - Nevermind Cassette', 'Nirvana', 'Music', 'Cassette', 12.49, 8, 'Nirvana - Nevermind Cassette е колекционерско издание на един от най-важните албуми в историята на алтернативния рок и запис, който промени посоката на масовата музика в началото на деветдесетте. Nevermind носи сурова енергия, мелодичност и емоционална директност, които превърнаха песни като Smells Like Teen Spirit, Come as You Are и Lithium в химни на цяло поколение. Форматът касета добавя допълнително ретро усещане към това заглавие и е особено подходящ за колекционери, които ценят физическите носители не само като източник на звук, но и като културен обект с характерна визия и дух на епохата. Аналоговият чар на касетата, включително леката суровост и механичното усещане при възпроизвеждане, пасва изненадващо добре на естетиката на албума и на гръндж настроението, което той носи. Това прави продукта интересен не само като сувенир, но и като реално слушаем формат за хора с касетофон в система, кола или домашна колекция. Nevermind е албум, който съчетава агресия и уязвимост по начин, рядко срещан в рок музиката, а именно това го прави актуален и днес. Касетното издание е и чудесен подарък за фен на Nirvana, защото добавя конкретна колекционерска стойност отвъд стандартния стрийминг достъп. Ако търсиш музикален продукт с историческа тежест, силна идентичност и формат, който носи допълнително усещане за епоха, Nirvana - Nevermind Cassette е много добро попадение. Това е малък носител с голямо културно значение и с онази сурова искреност, която направи албума безсмъртен.', 'images/products/nirvana-nevermind-cassette.jpg', 'Cassette', 'Rock', NULL, NULL, NULL, NULL, NULL, '2026-03-23 10:00:00', '2026-03-26 10:33:05'),
(32, 'Queen - Greatest Hits Collector Box', 'Queen', 'Music', 'Boxset', 44.90, 6, 'Queen - Greatest Hits Collector Box е колекционерско издание, което събира част от най-обичаните песни на Queen в премиум формат, подходящ както за дългогодишни фенове, така и за хора, които искат едно представително и силно заглавие с музика, разпознаваема от първите секунди. Queen са група с изключително широк диапазон от стилове, настроение и композиционна смелост, а именно greatest hits форматът позволява този диапазон да бъде усетен бързо и ярко чрез песни като Bohemian Rhapsody, Another One Bites the Dust, We Will Rock You и Radio Ga Ga. Collector box вариантът добавя стойност отвъд самото слушане, защото обикновено включва по-качествена опаковка, книжка, визуални материали или допълнителни елементи, които превръщат продукта в по-специален предмет за притежание и подаряване. Това е чудесен избор за домашна колекция, за витрина с любими артисти или за подарък на човек, който обича класическия рок, но предпочита цялостно, красиво поднесено издание. Музикално албумът предлага силно разнообразие: рок химни, поп влияние, театралност, хармонии и запомнящи се мелодии, които работят еднакво добре и днес. Точно затова подобна кутия не е просто компилация, а внимателно представено въведение към една от най-големите групи в историята. Ако търсиш продукт, който съчетава силен музикален каталог, естетика на колекционерски артикул и широка емоционална разпознаваемост, Queen - Greatest Hits Collector Box е много убедителен избор. Това е издание, което носи радост и като музика, и като предмет с присъствие, а подобна комбинация е рядка и ценна.', 'images/products/queen-greatest-hits-boxset.jpg', 'Boxset', 'Rock', NULL, NULL, NULL, NULL, NULL, '2026-03-23 10:00:00', '2026-03-26 10:33:05'),
(33, 'Movie Score Essentials Compilation', 'Various Artists', 'Music', 'Other', 16.50, 9, 'Movie Score Essentials Compilation е селекция, насочена към слушатели, които ценят силата на филмовата музика да създава образи, напрежение и емоция дори извън екрана. В подобна компилация обикновено се събират теми и откъси, които са се превърнали в разпознаваеми символи на киното, от епични оркестрови кулминации до по-интимни и меланхолични мелодии, свързани с конкретни сцени, герои и настроения. Това е продукт, който работи добре както за активно слушане, така и като фон за четене, работа и почивка, защото инструменталната музика от филми има способността да присъства силно, без непременно да доминира. Компилацията е особено подходяща за хора, които харесват оркестрово звучене, драматургичен размах и богати аранжименти, но не искат да се ограничават до музиката от един конкретен филм. Чрез такава подборка слушателят получава разнообразие от тоналности и емоционални регистри, което прави албума интересен и при многократно връщане към него. Ако изданието е на физически носител, то е и чудесен подарък за киномани, колекционери и фенове на саундтраци, защото съчетава познати теми с усещане за подбрана музикална антология. Подобен продукт има място не само в музикална, но и в тематична филмова колекция. Ако търсиш албум, който събира кинематографична атмосфера, силни оркестрови моменти и разнообразие от емоции в едно достъпно издание, Movie Score Essentials Compilation е удачен избор. Това е музика, която не се нуждае от картина, за да носи въображение, мащаб и въздействие.', 'images/products/movie-score-essentials.jpg', 'Compilation', 'Soundtrack', NULL, NULL, NULL, NULL, NULL, '2026-03-23 10:00:00', '2026-03-26 10:33:05'),
(34, 'MusicShop Logo Beanie', 'MusicShop', 'Merch', 'Headwear', 17.90, 18, 'MusicShop Logo Beanie е зимна шапка, създадена за ежедневен комфорт в студено време и за хора, които искат дискретен музикален акцент в стила си без прекалено натрапчив дизайн. Плетената ribbed структура помага шапката да приляга удобно към главата и да задържа топлината добре, което я прави практичен аксесоар за градско ходене, пътуване, сутрешни ангажименти и концертни вечери през есента и зимата. Материята е подбрана така, че да бъде достатъчно мека за директен контакт с кожата, без да създава неприятно усещане при по-продължително носене. Едноразмерният формат е удобен, защото позволява лесно прилягане при различни обиколки на главата, а еластичността помага шапката да стои стабилно, без да стяга излишно. Бродираното лого на MusicShop добавя по-изчистено и качествено присъствие в сравнение с обикновен печат и прави модела подходящ както за фенове на магазина, така и за хора, които просто харесват минималистичен аксесоар с музикален дух. Черният цвят е универсален и лесен за комбиниране с яке, худи, палто или по-спортна визия. Това е продукт, който има реална сезонна стойност и не е просто сувенир, защото се използва често и в различни ситуации. Подходящ е и за подарък, тъй като не изисква точен размер и влиза естествено в ежедневния гардероб. Ако търсиш практична зимна шапка с чист дизайн, добра носимост и умерен музикален характер, MusicShop Logo Beanie е разумен избор за студените месеци. Това е аксесоар, който съчетава топлина, удобство и идентичност в компактен и лесен за носене формат.', 'images/products/beanie_musicshop.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-23 10:00:00', '2026-03-26 10:33:05'),
(35, 'Arctic Monkeys Tour Poster', 'Arctic Monkeys', 'Merch', 'Posters', 8.90, 14, 'Arctic Monkeys Tour Poster е декоративен мърч артикул, предназначен за фенове, които искат да внесат атмосферата на концертна естетика и визуалния свят на групата в стая, студио, репетиционна или работно пространство. Постерът е с размер 50x70 см, което го прави достатъчно голям, за да бъде акцент на стената, без да изисква прекалено много място или специално оформление. Печатът върху матова хартия е важен детайл, защото намалява отблясъците и позволява изображението да се възприема по-приятно при различно осветление, включително лампа, дневна светлина или сценични светлини в творческо пространство. Тур плакатите обикновено носят специфична енергия, различна от стандартната рекламна визия, защото съчетават духа на живото изпълнение, графичен стил и усещане за конкретен музикален период. Именно това прави подобен постер по-личен и по-подходящ за хора, които не искат просто украса, а предмет с културен и фенски контекст. Arctic Monkeys имат силна визуална идентичност и подобен плакат работи добре както в минималистична стая, така и сред други музикални предмети като плочи, касети, книги и инструменти. Това е и добър подарък, защото е лесен за комбиниране с рамка и веднага променя атмосферата на помещението. Ако търсиш мърч, който добавя характер към интериора и показва музикален вкус по стилен начин, Arctic Monkeys Tour Poster е много добро решение. Това е продукт, който стои между декорация и колекционерски спомен, а точно в това се крие неговата привлекателност.', 'images/products/tour-poster.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-23 10:00:00', '2026-03-26 10:33:05'),
(36, 'Band Sticker Pack', 'Various Artists', 'Merch', 'Stickers', 5.50, 40, 'Band Sticker Pack е комплект с музикално вдъхновени стикери, предназначен за персонализиране на лаптопи, калъфи за инструменти, тефтери, куфари, бутилки и други повърхности, които могат да понесат малък визуален акцент с характер. Вместо един голям и фиксиран дизайн, пакетът предлага разнообразие от графики, което позволява всеки да избере къде и как да използва отделните елементи според собствения си стил. Подобни стикери са особено популярни сред музиканти, студенти и фенове на концертната култура, защото създават усещане за лична колекция и визуална свобода без голяма инвестиция. Гланцовото или защитено покритие е важно предимство, тъй като прави повърхността по-устойчива на ежедневно пипане, леко триене и нормално износване при носене в чанта или на открито. Разноцветният набор добавя динамика и позволява комбиниране на различни естетики, от класически рок мотиви до по-модерни музикални символи. Това прави пакета подходящ както за тийнейджъри, така и за възрастни фенове, които искат малко цвят и индивидуалност върху личните си вещи. Стикерите могат да се използват наведнъж или постепенно, което увеличава практическата стойност на продукта във времето. Те са и удобен малък подарък или допълнение към друга покупка като китара, плоча, калъф или тетрадка за уроци. Ако търсиш достъпен мърч продукт с визуално разнообразие и реално приложение в ежедневието, Band Sticker Pack е лек, забавен и много гъвкав избор. Това е тип аксесоар, който позволява на музикалния вкус да присъства в дребните детайли на деня по естествен и неформален начин.', 'images/products/band-sticker-pack.jpg', NULL, NULL, NULL, 'Multi', 'Sticker Pack', NULL, NULL, '2026-03-23 10:00:00', '2026-03-26 10:33:05'),
(37, 'MusicShop Canvas Tote Bag', 'MusicShop', 'Merch', 'Accessories', 13.90, 20, 'MusicShop Canvas Tote Bag е текстилен аксесоар, създаден за ежедневна употреба и особено подходящ за хора, които често носят книги, тетрадки, малки покупки, аксесоари или дори няколко плочи и искат по-устойчива алтернатива на тънките найлонови торбички. Платнената чанта има естествено, непретенциозно излъчване и се вписва еднакво добре в градски, учебен и творчески контекст, което я прави полезна далеч отвъд ролята на мърч продукт. Дръжките са достатъчно дълги за удобно носене на рамо или в ръка, а самото тяло на чантата предлага практичен вътрешен обем за предмети, които трябва да бъдат лесно достъпни през деня. Натуралният цвят на платното стои чисто и спокойно, а брандирането на MusicShop добавя идентичност без да натоварва визията. Това е особено важно за хора, които искат аксесоар, който може да се носи редовно и да се комбинира с различни дрехи и ситуации. Canvas материалът е предпочитан именно заради добрия баланс между лекота, здравина и възможност за многократна употреба. Така чантата е подходяща за пазаруване, за носене на кабели и дребна техника до репетиционна, за училище или просто за всекидневни задачи в града. Това я прави и отличен подарък, защото не зависи от размер, сезон или специална настройка. Ако търсиш практичен мърч продукт с дълъг живот и реално място в ежедневието, MusicShop Canvas Tote Bag е добър избор с приятен външен вид и полезен обем. Това е аксесоар, който съчетава функционалност, устойчив навик за повторна употреба и музикална идентичност в един прост, но много ефективен формат.', 'images/products/bag_musicshop.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-23 10:00:00', '2026-03-26 10:33:05'),
(38, 'Pedalboard Flight Case', 'RockBoard', 'Other', 'Cases', 59.90, 5, 'Pedalboard Flight Case е твърд транспортен куфар, предназначен да защитава ефекти, кабели и малки аксесоари при пренасяне между репетиционна, студио и сцена. За китаристи и басисти, които използват няколко педала и разчитат на тях за постоянен тон, сигурното съхранение и организация на оборудването са от голямо значение, а именно тук подобен flight case показва истинската си стойност. Твърдата конструкция предпазва съдържанието от удари, натиск и случайни щети по време на транспорт, докато вътрешната подложка или пяна помага педалите да останат стабилни и да не се търкат един в друг. Това е особено важно за музиканти, които често местят техника в автомобил, бус или обществен транспорт и не могат да си позволят повреден жак, счупено копче или разместен комплект преди участие. Черният външен вид е класически, ненатрапчив и професионален, а металните закопчалки и дръжката допринасят за усещането за надежден работен инструмент. Подобен куфар улеснява не само защитата, но и подреждането на сетъпа, защото всичко необходимо се събира на едно място и е готово за бързо разпъване. Това спестява време преди саундчек и намалява риска от забравени кабели или дребни части. Pedalboard Flight Case е подходящ както за активни концертни музиканти, така и за хора, които просто искат по-подредено и сигурно съхранение у дома. Ако държиш на техниката си и искаш тя да издържа по-дълго, този продукт е практична инвестиция, която носи спокойствие, организация и по-професионален подход към оборудването.', 'images/products/pedalboard-flight-case.jpg', NULL, NULL, NULL, 'Black', NULL, NULL, 'Case', '2026-03-23 10:00:00', '2026-03-26 10:33:05'),
(39, 'Vinyl Cleaning Kit', 'SpinCare', 'Other', 'Maintenance', 18.90, 16, 'Vinyl Cleaning Kit е комплект за поддръжка на грамофонни плочи, предназначен за колекционери и слушатели, които искат да запазят записа по-чист, по-тих и по-приятен за слушане във времето. Прахът, статичното електричество и фините замърсявания по каналите на плочата често водят до допълнително пращене, по-малко детайл и по-бързо износване както на самия носител, така и на иглата. Именно затова редовната, внимателна грижа е важна част от добрия навик при работа с винил. Подобен kit обикновено включва четка, почистваща течност и помощни аксесоари, които позволяват сухо или леко влажно почистване според нуждата, без агресивна намеса върху повърхността. Голямото предимство е, че слушателят може лесно да се погрижи за плочите си у дома между отделните пускания, вместо да чака замърсяването да се натрупа до степен, в която звукът да пострада осезаемо. Комплектът е особено полезен за хора, които купуват и употребявани плочи, защото там нуждата от освежаване и основно почистване е още по-голяма. Освен подобряване на звука, редовната поддръжка помага и самата колекция да изглежда по-добре и да се съхранява по-отговорно. Това е малък, но много важен аксесоар за всеки, който възприема винила не просто като декорация, а като носител, който трябва да се слуша и пази. Ако искаш любимите ти албуми да звучат по-чисто и да удължиш живота на плочите и грамофонната игла, Vinyl Cleaning Kit е разумен и необходим избор за всяка сериозна винилова колекция.', 'images/products/vinyl-cleaning-kit.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'Cleaning', '2026-03-23 10:00:00', '2026-03-26 10:33:05');

